insert into offmarket.business_signals (business_id, layer, signal_key, direction, weight, evidence, source, source_url, observed_at) values
('bbcc7927-8021-5f14-8191-e2377742f5c6', 2, 'rpls_license_skilled_trade_moat', 'positive', NULL, 'TX RPLS license = 4yr ABET-accredited surveying or equivalent + 4yr supervised survey-in-training + Tex. Occ. Code Ch. 1071 state exam. ~3,700 active RPLS statewide (TBPELS roster May 2026). Workforce documented as aging (TSPS workforce-shortage reports cite avg RPLS age >55).', 'tbpels_rpls_roster_aggregate', 'https://pels.texas.gov/roster/ls_rosters.html', '2026-05-16'),
('bbcc7927-8021-5f14-8191-e2377742f5c6', 3, 'solo_rpls_no_successor', 'positive', NULL, 'TBPELS firm roster + RPLS cross-reference shows exactly 1 active RPLS at firm #10009100 (GREGORY DEVIN SJERVEN) — no second RPLS added in 28yr tenure. No credentialed internal successor visible at the license-board level. NOTE: live team-page fetch required before A-tier promotion per skill non-negotiable.', 'tbpels_firm_rpls_join', 'https://tbpedownloads.s3-us-west-2.amazonaws.com/rpls_roster.csv', '2026-05-16'),
('bbcc7927-8021-5f14-8191-e2377742f5c6', 4, 'low_pe_attention_vertical', 'positive', NULL, 'TX land surveying = LOW-PE-ATTENTION vertical. Only Bowman Consulting (NASDAQ:BWMN) + Westwood Professional Services (Endeavour Capital) are PE-backed rollup platforms active in TX surveying. Large-AEC strategics (Stantec/WSP/AECOM/Kimley-Horn/Cobb Fendley/LJA) only bolt-on $5M+ rev firms. Sub-$5M independent universe (Kaufman, Kaufman County) structurally under-targeted = opportunity zone. ETA/search-fund appetite emerging fast 2024-2026 per Stanford Search Fund Study (top-15 ETA vertical).', 'verticals.md skill config + Stanford Search Fund Study + Bowman 10-K filings', 'https://pels.texas.gov/roster/ls_rosters.html', '2026-05-16'),
